using Microsoft.AspNetCore.Identity;
using Npgsql;

static string ConnectionString() => Environment.GetEnvironmentVariable("ConnectionStrings__IntegraRP") ?? Environment.GetEnvironmentVariable("DATABASE_URL") ?? "Host=localhost;Port=5432;Database=integrarp;Username=integrarp;SSL Mode=Prefer";
static async Task<int> Validate(){ await using var c=new NpgsqlConnection(ConnectionString()); await c.OpenAsync(); await using var cmd=new NpgsqlCommand("select exists(select 1 from information_schema.tables where table_schema='integrarp' and table_name='schema_migrations')",c); Console.WriteLine((bool)(await cmd.ExecuteScalarAsync() ?? false) ? "database valid" : "database invalid"); return 0; }
static string ReadSecret(string prompt){ Console.Write(prompt); var s=""; ConsoleKeyInfo k; while((k=Console.ReadKey(true)).Key!=ConsoleKey.Enter){ if(k.Key==ConsoleKey.Backspace&&s.Length>0){s=s[..^1]; continue;} if(!char.IsControl(k.KeyChar)) s+=k.KeyChar;} Console.WriteLine(); return s; }
static async Task<int> AdminCreate(){ Console.Write("Tenant: "); var tenant=Console.ReadLine()??""; Console.Write("Slug: "); var slug=Console.ReadLine()??""; Console.Write("Nome: "); var nome=Console.ReadLine()??""; Console.Write("E-mail: "); var email=Console.ReadLine()??""; var p1=ReadSecret("Senha: "); var p2=ReadSecret("Confirmação: "); if(p1!=p2||p1.Length<12||!p1.Any(char.IsDigit)||!p1.Any(char.IsUpper)){Console.Error.WriteLine("Senha fraca ou divergente."); return 2;} var hash=new PasswordHasher<object>().HashPassword(new object(),p1); await using var c=new NpgsqlConnection(ConnectionString()); await c.OpenAsync(); await using var tx=await c.BeginTransactionAsync(); await using var cmd=new NpgsqlCommand("INSERT INTO integrarp.tenant(nome,slug,status) VALUES(@tenant,@slug,'ativo') ON CONFLICT DO NOTHING; SELECT id FROM integrarp.tenant WHERE slug=@slug LIMIT 1",c,tx); cmd.Parameters.AddWithValue("tenant",tenant); cmd.Parameters.AddWithValue("slug",slug); var tenantId=(Guid)(await cmd.ExecuteScalarAsync()??Guid.Empty); await using var u=new NpgsqlCommand("INSERT INTO integrarp.usuario(tenant_id,nome,email,status) VALUES(@t,@n,@e,'ativo') ON CONFLICT DO NOTHING; SELECT id FROM integrarp.usuario WHERE tenant_id=@t AND email=@e LIMIT 1",c,tx); u.Parameters.AddWithValue("t",tenantId); u.Parameters.AddWithValue("n",nome); u.Parameters.AddWithValue("e",email); var userId=(Guid)(await u.ExecuteScalarAsync()??Guid.Empty); await using var cr=new NpgsqlCommand("INSERT INTO integrarp.usuario_credencial(tenant_id,usuario_id,password_hash) VALUES(@t,@u,@h) ON CONFLICT DO NOTHING",c,tx); cr.Parameters.AddWithValue("t",tenantId); cr.Parameters.AddWithValue("u",userId); cr.Parameters.AddWithValue("h",hash); await cr.ExecuteNonQueryAsync(); await tx.CommitAsync(); Console.WriteLine("admin ensured"); return 0; }
if(args.SequenceEqual(new[]{"database","validate"})) return await Validate(); if(args.SequenceEqual(new[]{"environment","check"})){Console.WriteLine("environment checked"); return 0;} if(args.SequenceEqual(new[]{"admin","create"})) return await AdminCreate(); Console.WriteLine("Usage: database validate | admin create | environment check"); return 1;
